prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?taskId ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?mid .
  FILTER(?mid = "1c273a0818b146269ac04f6b8d518698")

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bbo:id ?taskId . }
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?taskId ?choreo ?model WHERE {
  VALUES ?mid { "1c273a0818b146269ac04f6b8d518698" }

  ?model a bboExt:Model .
  {
    ?model tai:normalizedId ?mid .
  }
  UNION
  {
    ?model tai:originalId ?mid .
  }

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bbo:id ?taskId . }
}
ORDER BY COALESCE(?taskName, STR(?task))
LIMIT 25
